// Startup Validation logic (§327). Config is loaded from the configuration.*
// runtime cache (seeded from YAML, R-08) exposed to workflows as $vars/config.
// Secrets are read from env / n8n credentials only (§322, §324) — never inlined.
//
// This node performs the six §327 checks and returns a health_status contract
// plus a machine-readable validation report. It writes NOTHING to the DB here;
// persistence to monitoring.health_checks is a downstream node once Sprint 2
// creates that table. Until then the health record is returned to the caller.

const cfg = $vars || {};              // configuration.* runtime cache
const env = process.env || {};

const errors = [];

// 1. Required env secrets exist (§314, §322). Presence only — never value logging.
const requiredEnv = [
  'SUPABASE_URL', 'SUPABASE_SERVICE_KEY',
  'AZURE_DOCUMENT_INTELLIGENCE_ENDPOINT', 'AZURE_DOCUMENT_INTELLIGENCE_KEY',
  'OPENAI_API_KEY'
];
for (const k of requiredEnv) {
  if (!env[k] || String(env[k]).trim() === '') errors.push(`missing_env:${k}`);
}

// 2. Required config values exist (§327). Mirrors schemas/yaml/configuration.schema.json.
const need = {
  'ocr.provider': cfg.ocr && cfg.ocr.provider,
  'ocr.model': cfg.ocr && cfg.ocr.model,
  'llm.provider': cfg.llm && cfg.llm.provider,
  'llm.model': cfg.llm && cfg.llm.model,
  'embedding.provider': cfg.embedding && cfg.embedding.provider,
  'embedding.model': cfg.embedding && cfg.embedding.model,
  'embedding.dimensions': cfg.embedding && cfg.embedding.dimensions,
  'storage.provider': cfg.storage && cfg.storage.provider,
  'logging.logLevel': cfg.logging && cfg.logging.logLevel
};
for (const [k, v] of Object.entries(need)) {
  if (v === undefined || v === null || v === '') errors.push(`missing_config:${k}`);
}

// 3. Embedding dimension locked at 1536 for v1 (R-09).
if (cfg.embedding && cfg.embedding.dimensions !== undefined && Number(cfg.embedding.dimensions) !== 1536) {
  errors.push('embedding.dimensions_must_be_1536');
}

// 4. URLs valid (§327) — endpoint + Supabase URL are well-formed.
for (const u of [env.SUPABASE_URL, env.AZURE_DOCUMENT_INTELLIGENCE_ENDPOINT]) {
  if (u) { try { new URL(u); } catch (e) { errors.push(`invalid_url:${u.slice(0,8)}...`); } }
}

// 5. Feature flags valid (§312) — booleans only.
if (cfg.featureFlags) {
  for (const [k, v] of Object.entries(cfg.featureFlags)) {
    if (typeof v !== 'boolean') errors.push(`feature_flag_not_boolean:${k}`);
  }
}

// 6a. Vector index config valid (§227) — user-adjustable, startup-validated.
const vi = (cfg.embedding && cfg.embedding.vectorIndex) || {};
if (vi.type && ['hnsw','ivfflat'].indexOf(vi.type) === -1) errors.push('invalid_vector_index_type:'+vi.type);
if (vi.metric && ['cosine','l2','ip'].indexOf(vi.metric) === -1) errors.push('invalid_vector_index_metric:'+vi.metric);

// 6b. Authority-source model = 9 canonical sources (§439, R-16).
const auth = cfg.authoritySources;
if (!Array.isArray(auth) || auth.length !== 9) errors.push('authority_sources_must_have_9_entries');

// 6. Reranker gate (§305, R-12): if enabled, a cross-encoder model must be set.
if (cfg.retrieval && cfg.retrieval.rerankerEnabled === true &&
    (!cfg.retrieval.crossEncoderModel || cfg.retrieval.crossEncoderModel === '')) {
  errors.push('reranker_enabled_without_model');
}

const valid = errors.length === 0;
const state = valid ? 'Healthy' : 'Critical';

// health_status contract (crie/contracts/health_status). Provider states are set to
// the validation outcome; live provider pings are performed by the provider adapters
// (Module 18) which this workflow invokes in deployment. Until adapters run, states
// reflect configuration validity.
const health = {
  repository: state,
  ocr: state,
  llm: state,
  embeddingProvider: state,
  storage: state,
  database: state,
  n8n: 'Healthy',
  overall: state
};

return [{ json: {
  valid,
  errors,
  health,
  alert: valid ? null : { severity: 'Critical', reason: 'startup_validation_failed', errors },
  blockExecution: !valid
} }];
